sys_script.script:
/**
 * Create and update Time Tracking record
 * @author GEM/Quynhttn - 18.05.2026
 * @param {GlideRecord} current
 * @param {GlideRecord} previous
 * @returns {none}
 */
(function executeRule(current, previous /*null when async*/) {

	var grTimeTracking = new GlideRecord('x_1763182_talent_0_time_tracking');

	// Create new Time Tracking record
	if (current.operation() == 'insert') {
		createTimeTracking(grTimeTracking, current);
		return;
	}

	// Update Time Tracking when Assigned TA changes
	if (current.u_assigned_ta.changes()) {
		updateTimeTracking(grTimeTracking, current, current.sys_updated_on);
		createTimeTracking(grTimeTracking, current);
		return;
	}

	// Update close date
	if (current.u_actual_end_date.changes()) {
		updateTimeTracking(grTimeTracking, current, current.u_actual_end_date);
	}

})(current, previous);

/**
 * Create Time Tracking record
 * @param {GlideRecord} grTimeTracking
 * @param {GlideRecord} current
 * @returns {none}
 */
function createTimeTracking(grTimeTracking, current) {

	grTimeTracking.initialize();
	grTimeTracking.setValue('u_pic', current.u_assigned_ta);
	grTimeTracking.setValue('u_ticket_id', current.sys_id);
	grTimeTracking.setValue('u_open_date', current.u_start_date);
	grTimeTracking.setValue('u_active', true);
	grTimeTracking.insert();
}

/**
 * Update active Time Tracking record
 * @param {GlideRecord} grTimeTracking
 * @param {GlideRecord} current
 * @param {GlideDateTime} closeDate
 * @returns {none}
 */
function updateTimeTracking(grTimeTracking, current, closeDate) {

	grTimeTracking.addQuery('u_ticket_id', current.sys_id);
	grTimeTracking.addQuery('u_active', true);
	grTimeTracking.query();

	if (grTimeTracking.next()) {

		grTimeTracking.setValue('u_close_date', closeDate);

		var startDateGDT = GlideDateTime(grTimeTracking.u_open_date);
		var endDateGDT = GlideDateTime(closeDate);
		var totalTimeSpent = GlideDateTime.subtract(startDateGDT, endDateGDT);
		var totalTimeSpentInDays = Math.floor(totalTimeSpent.getNumericValue() / 86400000);

		grTimeTracking.setValue('u_total_time', totalTimeSpentInDays);
		grTimeTracking.setValue('u_active', false);
		grTimeTracking.update();
	}
}
